# PieChart with Custom Labels

```jsx
import {PieChart, Pie, Cell, Tooltip, Legend, ResponsiveContainer} from 'recharts';

const data = [
  {name: 'Group A', value: 400},
  {name: 'Group B', value: 300},
  {name: 'Group C', value: 300},
  {name: 'Group D', value: 200},
];
const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042'];

function SimplePieChart() {
  return (
    <ResponsiveContainer width="100%" height={300}>
      <PieChart>
        <Pie data={data} cx="50%" cy="50%" labelLine={false}
          label={({name, percent}) => `${name} ${(percent * 100).toFixed(0)}%`}
          outerRadius={80} fill="#8884d8" dataKey="value">
          {data.map((entry, index) => (
            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
          ))}
        </Pie>
        <Tooltip />
        <Legend />
      </PieChart>
    </ResponsiveContainer>
  );
}
```

**Category:** Charts
**URL:** https://recharts.org/en-US/api/PieChart

# Custom Tooltip

Two approaches: custom component or formatter props.

## Custom Component
```jsx
const CustomTooltip = ({active, payload, label}) => {
  if (active && payload && payload.length) {
    return (
      <div style={{backgroundColor: 'white', padding: '10px', border: '1px solid #ccc'}}>
        <p>{`Date: ${label}`}</p>
        {payload.map((entry, index) => (
          <p key={index} style={{color: entry.color}}>
            {`${entry.name}: $${entry.value.toLocaleString()}`}
          </p>
        ))}
      </div>
    );
  }
  return null;
};

<Tooltip content={<CustomTooltip />} cursor={{stroke: 'red', strokeWidth: 2}} />
```

## Formatter Props
```jsx
<Tooltip
  formatter={(value, name) => [`$${value.toLocaleString()}`, name]}
  labelFormatter={(label) => `Month: ${label}`}
/>
```

**Category:** Components
**URL:** https://recharts.org/en-US/api/Tooltip

# Brush - Data Zoom and Pan

Enable data range selection for zooming and panning.

```jsx
import {LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Brush, ResponsiveContainer} from 'recharts';

const data = Array.from({length: 50}, (_, i) => ({
  name: `Day ${i + 1}`,
  value: Math.floor(Math.random() * 1000) + 500
}));

function ChartWithBrush() {
  return (
    <ResponsiveContainer width="100%" height={400}>
      <LineChart data={data}>
        <CartesianGrid strokeDasharray="3 3" />
        <XAxis dataKey="name" />
        <YAxis />
        <Tooltip />
        <Line type="monotone" dataKey="value" stroke="#8884d8" dot={false} />
        <Brush dataKey="name" height={30} stroke="#8884d8" startIndex={0} endIndex={20} />
      </LineChart>
    </ResponsiveContainer>
  );
}
```

Props: dataKey, height, stroke, startIndex, endIndex, onChange.

**Category:** Components
**URL:** https://recharts.org/en-US/api/Brush

# Custom Bar Shape

Use the `shape` prop on Bar for custom rendering.

```tsx
const getPath = (x, y, width, height) =>
  `M${x},${y + height}
   C${x + width / 3},${y + height} ${x + width / 2},${y + height / 3} ${x + width / 2}, ${y}
   C${x + width / 2},${y + height / 3} ${x + (2 * width) / 3},${y + height} ${x + width}, ${y + height}
   Z`;

const TriangleBar = (props) => {
  const {fill, x, y, width, height} = props;
  return <path d={getPath(x, y, width, height)} stroke="none" fill={fill} />;
};

<Bar dataKey="uv" fill="#8884d8" shape={<TriangleBar />} />
```

**Category:** Components
**URL:** https://recharts.org/en-US/api/Bar

# AreaChart with Gradient Fills

```jsx
import {AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer} from 'recharts';

const data = [
  {name: 'Jan', uv: 4000, pv: 2400},
  {name: 'Feb', uv: 3000, pv: 1398},
  {name: 'Mar', uv: 2000, pv: 9800}
];

function GradientAreaChart() {
  return (
    <ResponsiveContainer width="100%" height={300}>
      <AreaChart data={data}>
        <defs>
          <linearGradient id="colorUv" x1="0" y1="0" x2="0" y2="1">
            <stop offset="5%" stopColor="#8884d8" stopOpacity={0.8}/>
            <stop offset="95%" stopColor="#8884d8" stopOpacity={0}/>
          </linearGradient>
        </defs>
        <CartesianGrid strokeDasharray="3 3" />
        <XAxis dataKey="name" /><YAxis />
        <Tooltip />
        <Area type="monotone" dataKey="uv" stroke="#8884d8" fillOpacity={1} fill="url(#colorUv)" />
      </AreaChart>
    </ResponsiveContainer>
  );
}
```

# RadarChart with Multiple Series

```jsx
import {RadarChart, Radar, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Legend, ResponsiveContainer} from 'recharts';

const data = [
  {subject: 'Math', A: 120, B: 110},
  {subject: 'English', A: 86, B: 130},
  {subject: 'Physics', A: 85, B: 90}
];

function SimpleRadarChart() {
  return (
    <ResponsiveContainer width="100%" height={300}>
      <RadarChart cx="50%" cy="50%" outerRadius="80%" data={data}>
        <PolarGrid />
        <PolarAngleAxis dataKey="subject" />
        <PolarRadiusAxis angle={30} domain={[0, 150]} />
        <Radar name="A" dataKey="A" stroke="#8884d8" fill="#8884d8" fillOpacity={0.6} />
        <Radar name="B" dataKey="B" stroke="#82ca9d" fill="#82ca9d" fillOpacity={0.6} />
        <Legend />
      </RadarChart>
    </ResponsiveContainer>
  );
}
```

# Interactive Legend with Toggle Visibility

```jsx
import {LineChart, Line, XAxis, YAxis, Legend, ResponsiveContainer} from 'recharts';
import {useState} from 'react';

function InteractiveLegend() {
  const [hiddenLines, setHiddenLines] = useState({});

  const handleClick = (dataKey) => 
    setHiddenLines(prev => ({...prev, [dataKey]: !prev[dataKey]}));

  const data = [
    {name: 'Jan', pv: 2400, uv: 4000},
    {name: 'Feb', pv: 1398, uv: 3000}
  ];

  return (
    <ResponsiveContainer width="100%" height={300}>
      <LineChart data={data}>
        <XAxis dataKey="name" />
        <YAxis />
        <Legend 
          onClick={(e) => handleClick(e.dataKey)} 
          wrapperStyle={{cursor: 'pointer'}} 
        />
        <Line dataKey="pv" stroke="#8884d8" hide={hiddenLines.pv} />
        <Line dataKey="uv" stroke="#82ca9d" hide={hiddenLines.uv} />
      </LineChart>
    </ResponsiveContainer>
  );
}
```
